{"code": "import json

# Load 2015 metadata
metadata_file = locals()['var_functions.query_db:90']
with open(metadata_file, 'r') as f:
    articles_2015_metadata = json.load(f)

# Create region mapping
region_map = {article['article_id']: article['region'] for article in articles_2015_metadata}

# Load article content (first batch of 1000, which includes 50 articles from 2015)
mongodb_file = locals()['var_functions.query_db:62']
with open(mongodb_file, 'r') as f:
    mongodb_articles = json.load(f)

# Filter to only 2015 articles
articles_2015 = [article for article in mongodb_articles if article['article_id'] in region_map]

# Enhanced category keywords based on what we learned
world_keywords = [
    'world', 'global', 'international', 'united nations', 'security council', 
    'war', 'peace', 'terrorism', 'conflict', 'crisis', 'diplomatic', 'aid',
    'refugee', 'summit', 'treaty', 'negotiation', 'embassy', 'ambassador',
    'diplomacy', 'peacekeeping', 'foreign', 'world leaders', 'global market',
    'what is', "what's in", 'report', 'study shows', 'research', 'survey'
]

sports_keywords = [
    'sport', 'game', 'olympic', 'world cup', 'championship', 'tournament', 
    'tennis', 'football', 'soccer', 'basketball', 'baseball', 'golf', 'athlete'
]

business_keywords = [
    'stock', 'market', 'economy', 'business', 'company', 'corporation', 
    'investment', 'wall st', 'nasdaq', 'profit', 'revenue', 'shares', 
    'trade deficit', 'oil prices', 'ipo', 'float', 'stock market'
]

tech_keywords = [
    'technology', 'tech', 'science', 'software', 'computer', 'digital', 
    'innovation', 'research', 'internet', 'it', 'google', 'hp', 'oracle',
    'hewl", "hewlett', "hewlett-packard"
]

# Categorize 2015 articles and count World category by region
world_articles_by_region = {}
category_counts_by_region = {}

for article in articles_2015:
    title_desc = (article.get('title', '') + ' ' + article.get('description', '')).lower()
    region = region_map[article['article_id']]

    # Determine category (in order of specificity)
    if any(keyword in title_desc for keyword in sports_keywords):
        category = 'Sports'
    elif any(keyword in title_desc for keyword in tech_keywords):
        category = 'Science/Technology'
    elif any(keyword in title_desc for keyword in business_keywords):
        category = 'Business'
    elif any(keyword in title_desc for keyword in world_keywords):
        category = 'World'
    else:
        category = 'Other'

    # Count by region and category
    if region not in category_counts_by_region:
        category_counts_by_region[region] = {'World': 0, 'Sports': 0, 'Business': 0, 'Science/Technology': 0, 'Other': 0}

    category_counts_by_region[region][category] += 1

    if category == 'World':
        if region not in world_articles_by_region:
            world_articles_by_region[region] = []
        world_articles_by_region[region].append({
            'article_id': article['article_id'],
            'title': article['title'],
            'region': region
        })

print('__RESULT__:')
print(json.dumps({
    'sample_size': len(articles_2015),
    'world_articles_by_region': {region: len(articles) for region, articles in world_articles_by_region.items()},
    'category_counts_total': category_counts_by_region,
    'world_articles_sample': list(world_articles_by_region.values())[0][:3] if world_articles_by_region else []
}))"}
